import { useState, useEffect } from "react";

function App() {
  const [files, setFiles] = useState([]);
  const [previews, setPreviews] = useState([]);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [darkMode, setDarkMode] = useState(false);
  const [adminMode, setAdminMode] = useState(false);
  const [animatedScore, setAnimatedScore] = useState(0);

  const claimId = `CLM-${Date.now()}`;

  useEffect(() => {
    if (result) {
      let start = 0;
      const end = result.fraud_confidence_score || 0;
      const duration = 1000;
      const stepTime = 20;
      const step = (end - start) / (duration / stepTime);

      const interval = setInterval(() => {
        start += step;
        if (start >= end) {
          start = end;
          clearInterval(interval);
        }
        setAnimatedScore(Math.round(start));
      }, stepTime);
    }
  }, [result]);

  const handleFiles = (e) => {
    const selected = Array.from(e.target.files);
    setFiles(selected);
    setPreviews(selected.map((file) => URL.createObjectURL(file)));
    setResult(null);
  };

  const handleUpload = async () => {
    if (!files.length) return;

    const formData = new FormData();
    files.forEach((file) => formData.append("file", file));

    setLoading(true);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });

      const data = await response.json();
      setResult(data);
    } catch (err) {
      console.error(err);
    }

    setLoading(false);
  };

  const riskLevel = (score) => {
    if (score <= 40) return "Low Risk";
    if (score <= 75) return "Medium Risk";
    return "High Risk";
  };

  const theme = darkMode ? darkStyles : lightStyles;

  return (
    <div style={theme.page}>
      <div style={theme.container}>

        {/* Header */}
        <header style={theme.header}>
          <h1>ClaimPilot AI</h1>

          <div style={{ display: "flex", gap: 15 }}>
            <button onClick={() => setDarkMode(!darkMode)} style={theme.toggle}>
              {darkMode ? "Light Mode" : "Dark Mode"}
            </button>

            <button onClick={() => setAdminMode(!adminMode)} style={theme.toggle}>
              {adminMode ? "User Mode" : "Admin Mode"}
            </button>
          </div>
        </header>

        {/* Upload Section */}
        <div style={theme.card}>
          <input type="file" multiple accept="image/*" onChange={handleFiles} />

          <div style={{ display: "flex", gap: 15, flexWrap: "wrap", marginTop: 20 }}>
            {previews.map((src, index) => (
              <img key={index} src={src} alt="preview" style={theme.preview} />
            ))}
          </div>

          <button onClick={handleUpload} style={theme.primaryBtn}>
            {loading ? "Analyzing..." : "Run AI Audit"}
          </button>
        </div>

        {/* Results */}
        {result && (
          <div style={theme.card}>
            <h2>Audit Summary</h2>
            <p>Claim ID: {claimId}</p>

            <h3>Total Estimate: PKR {result.total_estimate_pkr}</h3>

            <h3>
              Fraud Score: {animatedScore}% ({riskLevel(animatedScore)})
            </h3>

            {adminMode && (
              <div style={theme.adminPanel}>
                <h3>Admin Review Panel</h3>
                <textarea
                  placeholder="Add internal review notes..."
                  style={theme.textarea}
                />
                <button style={theme.primaryBtn}>
                  Approve Claim
                </button>
                <button style={theme.dangerBtn}>
                  Reject Claim
                </button>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

/* LIGHT THEME */
const lightStyles = {
  page: { minHeight: "100vh", background: "#f3f6fb", padding: 40 },
  container: { maxWidth: 1000, margin: "auto" },
  header: { display: "flex", justifyContent: "space-between" },
  card: {
    background: "#fff",
    padding: 25,
    borderRadius: 12,
    marginTop: 25,
  },
  preview: { width: 120, borderRadius: 8 },
  primaryBtn: {
    marginTop: 20,
    padding: "10px 20px",
    background: "#1e40af",
    color: "#fff",
    border: "none",
    borderRadius: 6,
  },
  toggle: {
    padding: "8px 15px",
    background: "#ddd",
    border: "none",
    borderRadius: 6,
  },
  adminPanel: { marginTop: 20 },
  textarea: { width: "100%", height: 80, marginBottom: 10 },
  dangerBtn: {
    marginLeft: 10,
    padding: "10px 20px",
    background: "#dc2626",
    color: "#fff",
    border: "none",
    borderRadius: 6,
  },
};

/* DARK THEME */
const darkStyles = {
  ...lightStyles,
  page: { minHeight: "100vh", background: "#0f172a", padding: 40, color: "#fff" },
  card: { background: "#1e293b", padding: 25, borderRadius: 12, marginTop: 25 },
  toggle: {
    padding: "8px 15px",
    background: "#334155",
    color: "#fff",
    border: "none",
    borderRadius: 6,
  },
};

export default App;
